import { Initializer, Model } from '@adobe-commerce/elsie/lib';
import { Lang } from '@adobe-commerce/elsie/i18n';
import { events } from '@adobe-commerce/event-bus';
import { initializeOrderDetails } from '../helpers/initializeOrderDetails';
import {
  CustomerOrdersReturnModel,
  OrderDataModel,
  RequestReturnModel,
} from '@/order/data/models';
import { redirectTo } from '@/order/lib/redirectTo';

export type ConfigProps = {
  langDefinitions?: Lang;
  models?: {
    OrderDataModel?: Model<OrderDataModel>;
    CustomerOrdersReturnModel?: Model<CustomerOrdersReturnModel>;
    RequestReturnModel?: Model<RequestReturnModel>;
  };
  orderRef?: string;
  returnRef?: string;
  orderData?: OrderDataModel | null;
  routeOrdersList?: () => string;
};

export const initialize = new Initializer<ConfigProps>({
  init: async (config) => {
    const defaultConfig = {};

    initialize.config.setConfig({ ...defaultConfig, ...config });
    initializeOrderDetails(config as ConfigProps).catch((error) =>
      console.error(error)
    );
  },

  listeners: () => [
    events.on('companyContext/changed', async () => {
      const config = initialize.config.getConfig();
      const {
        orderRef,
        returnRef,
        routeOrdersList = () => '/customer/orders',
      } = config;

      // Only refetch if we have an orderRef
      if (!orderRef) {
        return;
      }

      // Create temporary listeners to detect success or error
      let orderDataListener: any;
      let orderErrorListener: any;

      const cleanup = () => {
        orderDataListener?.off();
        orderErrorListener?.off();
      };

      // Listener to detect when the order is successfully reloaded
      orderDataListener = events.on('order/data', () => {
        // Order reloaded successfully, components will update automatically
        cleanup();
      });

      // Listener to detect error in refetch
      orderErrorListener = events.on('order/error', (error: any) => {
        // Only act if it's a network error (not a user error)
        if (error?.type === 'network') {
          redirectTo(routeOrdersList);
        }
        cleanup();
      });

      // Refetch order details (this will emit order/data or order/error)
      await initializeOrderDetails({
        orderRef,
        returnRef,
        orderData: null, // Force refetch instead of using cached data
      });
    }),
  ],
});

export const config = initialize.config;
