import { GUEST_ORDER_FRAGMENT, RETURNS_FRAGMENT } from '@/order/api/fragments';

export const GET_GUEST_ORDER = /* GraphQL */ `
  query GET_GUEST_ORDER($input: GuestOrderInformationInput!) {
    guestOrder(input: $input) {
      ...GUEST_ORDER_FRAGMENT
      returns {
        ...RETURNS_FRAGMENT
      }
    }
  }
  ${GUEST_ORDER_FRAGMENT}
  ${RETURNS_FRAGMENT}
`;
