import { OrderAddressModel } from '@/order/data/models';

export function transformCustomerAddressInput(address: OrderAddressModel) {
  return {
    region: {
      region_id: address?.regionId ? Number(address?.regionId) : null,
      region: address?.region,
    },
    city: address?.city,
    company: address?.company,
    country_code: address?.countryCode,
    firstname: address?.firstName,
    lastname: address?.lastName,
    middlename: address?.middleName,
    postcode: address?.postCode,
    street: address?.street,
    telephone: address?.telephone,
    custom_attributesV2:
      address?.customAttributes?.map((attr) => ({
        attribute_code: attr.code,
        value: attr.value,
      })) || [],
  };
}
