import { CONFIRM_CANCEL_ORDER_MUTATION } from '@/order/api/confirmCancelOrder/graphql/ConfirmCancelOrder';
import { events } from '@adobe-commerce/event-bus';
import { fetchGraphQl } from '@/order/api';
import { handleFetchError } from '@/order/lib/fetch-error';
import { OrderDataModel } from '@/order/data/models';
import { transformOrderData } from '@/order/data/transforms';

export const confirmCancelOrder = async (
  orderId: string,
  confirmationKey: string
) => {
  return fetchGraphQl(CONFIRM_CANCEL_ORDER_MUTATION, {
    variables: {
      orderId,
      confirmationKey,
    },
  }).then(async ({ errors, data }) => {
    const _errors = [
      ...(data?.confirmCancelOrder?.errorV2
        ? [data?.confirmCancelOrder?.errorV2]
        : []),
      ...(errors ?? []),
    ];

    let payload: OrderDataModel | null = null;

    if (data?.confirmCancelOrder?.order) {
      payload = transformOrderData(data?.confirmCancelOrder?.order);
      events.emit('order/data', payload as OrderDataModel);
    }

    if (_errors.length > 0) {
      return handleFetchError(_errors);
    }

    return payload;
  });
};
