import { fetchGraphQl } from '@/order/api/fetch-graphql';
import { handleNetworkError } from '@/order/lib/network-error';
import { GET_GUEST_ORDER } from './graphql/getGuestOrder.graphql';
import { GuestOrderResponse } from '@/order/types';
import { transformGuestOrder } from '@/order/data/transforms';
import { OrderDataModel } from '@/order/data/models';
import { handleFetchError } from '@/order/lib/fetch-error';

export const getGuestOrder = async (form: {
  number: string;
  email: string;
  lastname: string;
}): Promise<OrderDataModel | null> => {
  return await fetchGraphQl(GET_GUEST_ORDER, {
    method: 'GET',
    cache: 'no-cache',
    variables: {
      input: form,
    },
  })
    .then((response: GuestOrderResponse) => {
      if (
        response.errors?.length &&
        response.errors[0].message === 'Please login to view the order.'
      ) {
        return handleFetchError(response.errors);
      }

      return transformGuestOrder(response);
    })
    .catch(handleNetworkError);
};
