import { fetchGraphQl } from '@/order/api';
import { REQUEST_GUEST_ORDER_CANCEL_MUTATION } from './graphql/requestGuestOrderCancelMutation';
import { handleFetchError } from '@/order/lib/fetch-error';
import { transformOrderData } from '@/order/data/transforms';

export const requestGuestOrderCancel = async (
  token: string,
  reason: string,
  onSuccess: Function,
  onError: Function
): Promise<void> => {
  if (!token) throw new Error('No order token found');
  if (!reason) throw new Error('No reason found');

  return fetchGraphQl(REQUEST_GUEST_ORDER_CANCEL_MUTATION, {
    variables: {
      token,
      reason,
    },
  })
    .then(({ errors, data }) => {
      if (errors) return handleFetchError(errors);
      if (data.requestGuestOrderCancel.error != null) {
        onError();
      }
      const orderData = transformOrderData(data.requestGuestOrderCancel.order);
      onSuccess(orderData);
    })
    .catch(() => onError());
};
