import { fetchGraphQl } from '@/order/api';
import { ORDER_BY_NUMBER } from './graphql/orderByNumber.graphql';
import { handleNetworkError } from '@/order/lib/network-error';
import {
  QueryType,
  ResponseData,
  GetOrderDetailsByIdProps,
} from '@/order/types';
import { transformOrderDetails } from '@/order/data/transforms';
import { TransformedData } from '@/order/data/models';

export const getOrderDetailsById = async <T extends QueryType>({
  orderId,
  returnRef,
  queryType,
  returnsPageSize = 50,
}: GetOrderDetailsByIdProps): Promise<TransformedData<T>> => {
  return await fetchGraphQl(ORDER_BY_NUMBER, {
    method: 'GET',
    cache: 'force-cache',
    variables: { orderNumber: orderId, pageSize: returnsPageSize },
  })
    .then((response) => {
      return transformOrderDetails(
        queryType ?? 'orderData',
        response as ResponseData<T>,
        returnRef
      );
    })
    .catch(handleNetworkError);
};
