import { fetchGraphQl } from '../fetch-graphql';
import { GET_ATTRIBUTES_LIST } from './graphql/getAttributesList.graphql';
import { handleNetworkError } from '@/order/lib/network-error';
import { handleFetchError } from '@/order/lib/fetch-error';
import { transformAttributesForm } from '@/order/data/transforms';
import { AttributesFormModel } from '@/order/data/models';
import { GetAttributesListResponse } from '@/order/types';

export const getAttributesList = async (
  entityType: string
): Promise<AttributesFormModel[] | []> => {
  return await fetchGraphQl(GET_ATTRIBUTES_LIST, {
    method: 'GET',
    cache: 'force-cache',
    variables: { entityType },
  })
    .then((response: GetAttributesListResponse) => {
      if (response.errors?.length) return handleFetchError(response.errors);

      return transformAttributesForm(response?.data?.attributesList?.items);
    })
    .catch(handleNetworkError);
};
