import { config } from '@/order/api';
import {
  OrderItemProps,
  OrderProps,
  ProductProps,
  QueryType,
  ResponseData,
} from '@/order/types';
import { merge } from '@adobe-commerce/elsie/lib';
import {
  OrderDataModel,
  OrderItemModel,
  OrderItemProductModel,
  TransformedData,
} from '../models';
import { transformCustomerOrdersReturns } from './transform-customer-orders-returns';

const parseNumber = (value: number | undefined | null) => {
  return value || 0;
};

const transformProduct = (product: ProductProps): OrderItemProductModel => {
  return {
    __typename: product?.__typename || '',
    uid: product?.uid || '',
    onlyXLeftInStock: product?.only_x_left_in_stock ?? 0,
    stockStatus: product?.stock_status ?? '',
    priceRange: {
      maximumPrice: {
        regularPrice: {
          currency:
            product?.price_range?.maximum_price?.regular_price?.currency ?? '',
          value: product?.price_range?.maximum_price?.regular_price?.value ?? 0,
        },
      },
    },
    canonicalUrl: product?.canonical_url ?? '',
    urlKey: product?.url_key || '',
    id: product?.uid ?? '',
    name: product?.name || '',
    sku: product?.sku || '',
    image: product?.image?.url || '',
    productType: product?.__typename || '',
    thumbnail: {
      label: product?.thumbnail?.label || '',
      url: product?.thumbnail?.url || '',
    },
  };
};

export const transformConfigurableOptions = (item: OrderItemProps) => {
  if (!item) return;

  if (!('selected_options' in item)) return;

  const configurableOptions: Record<string, string> = {};

  for (const option of item.selected_options!) {
    configurableOptions[option!.label] = option!.value;
  }

  return configurableOptions;
};

export const transformBundleOptions = (data: any) => {
  const bundle = data?.map((option: any) => ({
    uid: option.uid,
    label: option.label,
    values: option.values.map((value: any) => value.product_name).join(', '),
  }));

  const bundleOptions: { [key: string]: any } = {};

  bundle?.forEach((option: any) => {
    bundleOptions[option.label] = option.values;
  });

  return Object.keys(bundleOptions).length > 0 ? bundleOptions : null;
};

export const transformLinks = (links: { title: string }[]) => {
  return links?.length > 0
    ? {
        count: links.length,
        result: links.map((link: any) => link.title).join(', '),
      }
    : null;
};

const getQuantities = (orderItem: OrderItemProps) => {
  return {
    quantityCanceled: orderItem?.quantity_canceled ?? 0,
    quantityInvoiced: orderItem?.quantity_invoiced ?? 0,
    quantityOrdered: orderItem?.quantity_ordered ?? 0,
    quantityRefunded: orderItem?.quantity_refunded ?? 0,
    quantityReturned: orderItem?.quantity_returned ?? 0,
    quantityShipped: orderItem?.quantity_shipped ?? 0,
    quantityReturnRequested: orderItem?.quantity_return_requested ?? 0,
  };
};

const transformUserInformation = (user: any) => {
  return {
    firstName: user?.firstname ?? '',
    lastName: user?.lastname ?? '',
    middleName: user?.middlename ?? '',
  };
};

const transformAddress = (address: any) => {
  const { firstName, lastName, middleName } = transformUserInformation(address);

  return {
    firstName,
    lastName,
    middleName,
    city: address?.city ?? '',
    company: address?.company ?? '',
    country: address?.country ?? '',
    countryCode: address?.country_code ?? '',
    fax: address?.fax ?? '',
    postCode: address?.postcode ?? '',
    prefix: address?.prefix ?? '',
    region: address?.region ?? '',
    regionId: address?.region_id ?? '',
    street: address?.street ?? [],
    suffix: address?.suffix ?? '',
    telephone: address?.telephone ?? '',
    vatId: address?.vat_id ?? '',
    customAttributes: address?.custom_attributes ?? [],
  };
};

const transformTotal = (total: any) => {
  const defaultPriceData = {
    value: 0,
    currency: 'USD',
  };

  return {
    grandTotal: total?.grand_total ?? defaultPriceData,
    grandTotalExclTax: total?.grand_total_excl_tax ?? defaultPriceData,
    totalGiftCard: total?.total_giftcard ?? defaultPriceData,
    subtotalExclTax: total?.subtotal_excl_tax ?? defaultPriceData,
    subtotalInclTax: total?.subtotal_incl_tax ?? defaultPriceData,
    taxes: total?.taxes ?? [],
    totalTax: total?.total_tax ?? defaultPriceData,
    totalShipping: total?.total_shipping ?? defaultPriceData,
    discounts: total?.discounts ?? [],
  };
};

const transformPrice = (orderItem: any) => {
  const initialData = {
    value: 0,
    currency: 'USD',
  };
  const prices = orderItem?.prices ?? {};

  return {
    price: prices?.price ?? initialData,
    priceIncludingTax: prices?.price_including_tax ?? initialData,
    originalPrice: prices?.original_price ?? initialData,
    originalPriceIncludingTax:
      prices?.original_price_including_tax ?? initialData,
    discounts: prices?.discounts ?? [],
  };
};

const transformTaxCalculations = (
  itemPrices: any,
  productPrice: { value: number; currency: string },
  discounted: boolean
) => {
  const price = itemPrices?.price;
  const priceIncludingTax = itemPrices?.priceIncludingTax;
  const originalPrice = itemPrices?.originalPrice;

  const baseOriginalPriceValue = discounted
    ? originalPrice?.value
    : priceIncludingTax?.value;

  const includeAndExcludeTax = {
    originalPrice,
    baseOriginalPrice: {
      value: baseOriginalPriceValue,
      currency: originalPrice?.currency,
    },
    baseDiscountedPrice: {
      value: priceIncludingTax?.value,
      currency: priceIncludingTax?.currency,
    },
    baseExcludingTax: {
      value: price?.value,
      currency: price?.currency,
    },
  };
  const excludeTax = {
    originalPrice,
    baseOriginalPrice: {
      value: originalPrice?.value,
      currency: priceIncludingTax?.currency,
    },
    baseDiscountedPrice: {
      value: productPrice?.value,
      currency: price?.currency,
    },
    baseExcludingTax: {
      value: price?.value,
      currency: price?.currency,
    },
  };
  const includeTax = {
    singleItemPrice: {
      value: discounted ? originalPrice.value : priceIncludingTax.value,
      currency: priceIncludingTax.currency,
    },
    baseOriginalPrice: {
      value: baseOriginalPriceValue,
      currency: priceIncludingTax.currency,
    },
    baseDiscountedPrice: {
      value: priceIncludingTax.value,
      currency: priceIncludingTax.currency,
    },
  };

  return {
    includeAndExcludeTax,
    excludeTax,
    includeTax,
  };
};

const transformGiftCard = (orderItem: any) => {
  return {
    senderName: orderItem.gift_card?.sender_name || '',
    senderEmail: orderItem.gift_card?.sender_email || '',
    recipientEmail: orderItem.gift_card?.recipient_email || '',
    recipientName: orderItem.gift_card?.recipient_name || '',
    message: orderItem.gift_card?.message || '',
  };
};

const transformThumbnail = (orderItem: any) => {
  return {
    label: orderItem?.product?.thumbnail?.label || '',
    url: orderItem?.product?.thumbnail?.url || '',
  };
};

function transformWrappingPrice(data: any) {
  return {
    currency: data?.currency ?? 'USD',
    value: data?.value ?? 0,
  };
}

function transformGiftMessage(data: any) {
  return {
    senderName: data?.gift_message?.from ?? '',
    recipientName: data?.gift_message?.to ?? '',
    message: data?.gift_message?.message ?? '',
  };
}

function transformGiftWrapping(data: any) {
  return {
    design: data?.gift_wrapping?.design ?? '',
    uid: data?.gift_wrapping?.uid,
    selected: Boolean(data?.gift_wrapping?.uid),
    image: {
      url: data?.gift_wrapping?.image?.url ?? '',
      label: data?.gift_wrapping?.image?.label ?? '',
    },
    price: {
      currency: data?.gift_wrapping?.price?.currency ?? 'USD',
      value: data?.gift_wrapping?.price?.value ?? 0,
    },
  };
}

const transformOrderItem = (orderItem: any): OrderItemModel => {
  const {
    quantityCanceled,
    quantityInvoiced,
    quantityOrdered,
    quantityRefunded,
    quantityReturned,
    quantityShipped,
    quantityReturnRequested,
  } = getQuantities(orderItem);

  const itemPrices = transformPrice(orderItem);
  const discounted =
    orderItem?.prices?.original_price.value * orderItem?.quantity_ordered >
    orderItem?.prices?.price.value * orderItem?.quantity_ordered;
  const totalQuantity = parseNumber(orderItem?.quantity_ordered);
  const price = {
    value: orderItem?.product_sale_price?.value || 0,
    currency: orderItem?.product_sale_price?.currency,
  };

  return {
    giftMessage: transformGiftMessage(orderItem),
    giftWrappingAvailable: orderItem?.product?.gift_wrapping_available ?? false,
    giftWrappingPrice: transformWrappingPrice(
      orderItem?.product?.gift_wrapping_price
    ),
    productGiftWrapping: [transformGiftWrapping(orderItem)],
    selectedOptions: orderItem?.selected_options ?? [],
    productSalePrice: orderItem?.product_sale_price,
    status: orderItem?.status ?? '',
    type: orderItem?.__typename!,
    eligibleForReturn: orderItem?.eligible_for_return ?? false,
    productSku: orderItem?.product_sku ?? '',
    productName: orderItem?.product_name ?? '',
    productUrlKey: orderItem?.product_url_key ?? '',
    quantityCanceled,
    quantityInvoiced,
    quantityOrdered,
    quantityRefunded,
    quantityReturned,
    quantityShipped,
    quantityReturnRequested,
    id: orderItem?.id!,
    discounted,
    total: {
      value:
        orderItem?.product_sale_price?.value * orderItem?.quantity_ordered || 0,
      currency: orderItem?.product_sale_price?.currency || '',
    },
    totalInclTax: {
      value:
        orderItem?.product_sale_price?.value * orderItem?.quantity_ordered || 0,
      currency: orderItem?.product_sale_price?.currency,
    },
    price,
    prices: transformPrice(orderItem),
    itemPrices,
    taxCalculations: transformTaxCalculations(itemPrices, price, discounted),
    priceInclTax: {
      value: orderItem?.product_sale_price?.value ?? 0,
      currency: orderItem?.product_sale_price?.currency,
    },
    totalQuantity,
    regularPrice: {
      value:
        orderItem?.product?.price_range?.maximum_price?.regular_price?.value,
      currency:
        orderItem?.product?.price_range?.maximum_price?.regular_price?.currency,
    },
    product: transformProduct(orderItem?.product),
    thumbnail: transformThumbnail(orderItem),
    giftCard:
      orderItem?.__typename === 'GiftCardOrderItem'
        ? transformGiftCard(orderItem)
        : undefined,
    configurableOptions: transformConfigurableOptions(orderItem),
    bundleOptions:
      orderItem.__typename === 'BundleOrderItem'
        ? transformBundleOptions(orderItem.bundle_options)
        : null,
    downloadableLinks:
      orderItem.__typename === 'DownloadableOrderItem'
        ? transformLinks(orderItem?.downloadable_links)
        : null,
  };
};

export const transformOrderItems = (
  items: OrderItemProps[]
): OrderItemModel[] => {
  return items
    ?.filter((el) => el.__typename)
    .map((orderItem) => {
      return transformOrderItem(orderItem);
    });
};

const transformBasicOptions = (orderData: OrderProps) => {
  return {
    token: orderData?.token ?? '',
    email: orderData?.email ?? '',
    status: orderData?.status ?? '',
    number: orderData?.number ?? '',
    id: orderData?.id ?? '',
    carrier: orderData.carrier ?? '',
    coupons: orderData?.applied_coupons ?? [],
    orderDate: orderData?.order_date ?? '',
    isVirtual: orderData?.is_virtual ?? false,
    availableActions: orderData?.available_actions ?? [],
    orderStatusChangeDate: orderData?.order_status_change_date ?? '',
    shippingMethod: orderData?.shipping_method ?? '',
    adminAssistedOrder: orderData?.admin_assisted_order != null,
    giftWrappingOrder: {
      price: {
        value: orderData?.gift_wrapping?.price?.value ?? 0,
        currency: orderData?.gift_wrapping?.price?.currency ?? 'USD',
      },
      uid: orderData?.gift_wrapping?.uid ?? '',
    },
  };
};

const transformGiftOptions = (orderData: OrderProps) => {
  const giftOptions = orderData?.total?.gift_options;

  return {
    giftWrappingForItems: {
      value: giftOptions?.gift_wrapping_for_items?.value ?? 0,
      currency: giftOptions?.gift_wrapping_for_items?.currency ?? 'USD',
    },
    giftWrappingForItemsInclTax: {
      value: giftOptions?.gift_wrapping_for_items_incl_tax?.value ?? 0,
      currency:
        giftOptions?.gift_wrapping_for_items_incl_tax?.currency ?? 'USD',
    },
    giftWrappingForOrder: {
      value: giftOptions?.gift_wrapping_for_order?.value ?? 0,
      currency: giftOptions?.gift_wrapping_for_order?.currency ?? 'USD',
    },
    giftWrappingForOrderInclTax: {
      value: giftOptions?.gift_wrapping_for_order_incl_tax?.value ?? 0,
      currency:
        giftOptions?.gift_wrapping_for_order_incl_tax?.currency ?? 'USD',
    },
    printedCard: {
      value: giftOptions?.printed_card?.value ?? 0,
      currency: giftOptions?.printed_card?.currency ?? 'USD',
    },
    printedCardInclTax: {
      value: giftOptions?.printed_card_incl_tax?.value ?? 0,
      currency: giftOptions?.printed_card_incl_tax?.currency ?? 'USD',
    },
  };
};

export const transformAppliedGiftCards = (appliedGiftCards: any[] = []) => {
  if (!appliedGiftCards) return [];

  return appliedGiftCards?.map((giftCard: any) => ({
    code: giftCard?.code ?? '',
    appliedBalance: {
      value: giftCard.applied_balance?.value ?? 0,
      currency: giftCard.applied_balance?.currency ?? 'USD',
    },
  }));
};

export const transformOrderData = (
  orderData: OrderProps,
  returnRef?: string
): OrderDataModel => {
  const initialData = transformBasicOptions(orderData);
  const billingAddress = transformAddress(orderData?.billing_address);
  const shippingAddress = transformAddress(orderData?.shipping_address);
  const shipments = orderData.shipments?.map((item) => {
    return {
      ...item,
      items: item.items.map((el) => ({
        id: el.id,
        productName: el.product_name,
        productSku: el.product_sku,
        quantityShipped: el.quantity_shipped,
        orderItem: transformOrderItem(el.order_item),
      })),
    };
  });

  const appliedGiftCards = transformAppliedGiftCards(
    orderData?.applied_gift_cards
  );
  const items = transformOrderItems(orderData.items);
  const comments = orderData?.comments?.map((c) => ({
    message: c?.message ?? '',
    timestamp: c?.timestamp ?? '',
  })) ?? [];
  const modifyReturns =
    transformCustomerOrdersReturns(orderData?.returns)?.ordersReturn ?? [];
  const returns = returnRef
    ? modifyReturns.filter((el) => el.returnNumber === returnRef)
    : modifyReturns;
  const itemsEligibleForReturn = transformOrderItems(
    orderData.items_eligible_for_return
  );
  const total = transformTotal(orderData?.total);
  const selectedPaymentMethod = orderData?.payment_methods?.[0];
  const shippingMethod = orderData?.shipping_method;
  const totalQuantity = items?.reduce(
    (accum: number, item: OrderItemModel) => accum + item?.totalQuantity,
    0
  );
  const shipping = {
    amount: total?.totalShipping?.value ?? 0,
    currency: total?.totalShipping?.currency || '',
    code: initialData?.shippingMethod ?? '',
  };
  const payments = [
    {
      code: selectedPaymentMethod?.type ?? '',
      name: selectedPaymentMethod?.name ?? '',
    },
  ];
  const subtotalExclTax = total?.subtotalExclTax;
  const subtotalInclTax = total?.subtotalInclTax;
  const totalGiftOptions = transformGiftOptions(orderData);
  const giftMessage = transformGiftMessage(orderData);
  const cartGiftWrapping = [transformGiftWrapping(orderData)];
  const printedCardIncluded = orderData?.printed_card_included ?? false;
  const giftReceiptIncluded = orderData?.gift_receipt_included ?? false;

  const model = {
    ...initialData,
    ...total,
    giftMessage,
    cartGiftWrapping,
    printedCardIncluded,
    giftReceiptIncluded,
    appliedGiftCards,
    totalGiftOptions,
    subtotalExclTax,
    subtotalInclTax,
    billingAddress,
    shippingAddress,
    shipments,
    items,
    comments,
    returns,
    itemsEligibleForReturn,
    totalQuantity,
    shippingMethod,
    shipping,
    payments,
  };

  return merge(
    model, // default transformer
    config?.getConfig()?.models?.OrderDataModel?.transformer?.(orderData) // custom transformer
  );
};

export const transformOrderDetails = <T extends QueryType>(
  queryType: QueryType,
  response: ResponseData<T>,
  returnRef?: string
): TransformedData<T> => {
  if (
    response?.data?.customer?.orders?.items?.length &&
    queryType === 'orderData'
  ) {
    const item = response?.data?.customer?.orders?.items[0];

    return transformOrderData(item, returnRef) as TransformedData<T>;
  }

  return null as TransformedData<T>;
};
