import {
  ADDRESS_FRAGMENT,
  ORDER_SUMMARY_FRAGMENT,
  ORDER_ITEM_DETAILS_FRAGMENT,
  PRODUCT_DETAILS_FRAGMENT,
  GIFT_CARD_DETAILS_FRAGMENT,
  PRICE_DETAILS_FRAGMENT,
  BUNDLE_ORDER_ITEM_DETAILS_FRAGMENT,
  ORDER_ITEM_FRAGMENT,
  GIFT_WRAPPING_FRAGMENT,
  GIFT_MESSAGE_FRAGMENT,
} from '@/order/api/fragments';

export const CANCEL_ORDER_MUTATION = /* GraphQL */ `
  mutation CANCEL_ORDER_MUTATION($orderId: ID!, $reason: String!) {
    cancelOrder(input: { order_id: $orderId, reason: $reason }) {
      error
      order {
        email
        available_actions
        status
        number
        id
        order_date
        carrier
        shipping_method
        is_virtual
        applied_coupons {
          code
        }
        shipments {
          id
          number
          tracking {
            title
            number
            carrier
          }
          comments {
            message
            timestamp
          }
          items {
            id
            product_sku
            product_name
            order_item {
              ...ORDER_ITEM_DETAILS_FRAGMENT
              ... on GiftCardOrderItem {
                ...GIFT_CARD_DETAILS_FRAGMENT
                product {
                  ...PRODUCT_DETAILS_FRAGMENT
                }
              }
            }
          }
        }
        payment_methods {
          name
          type
        }
        shipping_address {
          ...ADDRESS_FRAGMENT
        }
        billing_address {
          ...ADDRESS_FRAGMENT
        }
        items {
          ...ORDER_ITEM_FRAGMENT
        }
        total {
          ...ORDER_SUMMARY_FRAGMENT
        }
      }
    }
  }
  ${PRODUCT_DETAILS_FRAGMENT}
  ${PRICE_DETAILS_FRAGMENT}
  ${GIFT_CARD_DETAILS_FRAGMENT}
  ${ORDER_ITEM_DETAILS_FRAGMENT}
  ${BUNDLE_ORDER_ITEM_DETAILS_FRAGMENT}
  ${ORDER_SUMMARY_FRAGMENT}
  ${ADDRESS_FRAGMENT}
  ${ORDER_ITEM_FRAGMENT}
  ${GIFT_WRAPPING_FRAGMENT}
  ${GIFT_MESSAGE_FRAGMENT}
`;
