import { CUSTOMER_ORDER_FRAGMENT } from '@/order/api/graphql/CustomerOrderFragment.graphql';
import { RETURNS_FRAGMENT } from '@/order/api/fragments';

export const ORDER_BY_NUMBER = /* GraphQL */ `
  query ORDER_BY_NUMBER($orderNumber: String!, $pageSize: Int) {
    customer {
      orders(filter: { number: { eq: $orderNumber } }) {
        items {
          ...CUSTOMER_ORDER_FRAGMENT
          returns(pageSize: $pageSize) {
            ...RETURNS_FRAGMENT
          }
          items_eligible_for_return {
            ...ORDER_ITEM_FRAGMENT
          }
        }
      }
    }
  }
  ${CUSTOMER_ORDER_FRAGMENT}
  ${RETURNS_FRAGMENT}
`;
