import { GUEST_ORDER_FRAGMENT } from '@/order/api/fragments';

export const REQUEST_GUEST_ORDER_CANCEL_MUTATION = /* GraphQL */ `
  mutation REQUEST_GUEST_ORDER_CANCEL_MUTATION(
    $token: String!
    $reason: String!
  ) {
    requestGuestOrderCancel(input: { token: $token, reason: $reason }) {
      error
      order {
        ...GUEST_ORDER_FRAGMENT
      }
    }
  }
  ${GUEST_ORDER_FRAGMENT}
`;
