import { handleNetworkError } from '@/order/lib/network-error';
import { fetchGraphQl } from '@/order/api/fetch-graphql';
import { handleFetchError } from '@/order/lib/fetch-error';
import { REORDER_ITEMS_MUTATION } from './graphql/reorderItems.graphql';
import {
  ReorderItemsProps,
  ReorderItemsResponse,
} from '@/order/types/api/reorderItems.types';

export const reorderItems = async (
  orderNumber: string
): Promise<ReorderItemsProps> => {
  return await fetchGraphQl(REORDER_ITEMS_MUTATION, {
    method: 'POST',
    variables: { orderNumber },
  })
    .then((response: ReorderItemsResponse) => {
      if (response.errors?.length) return handleFetchError(response.errors);

      const success =
        !!response?.data?.reorderItems?.cart?.itemsV2.items.length;
      const userInputErrors =
        response?.data?.reorderItems?.userInputErrors ?? [];

      return { success, userInputErrors };
    })
    .catch(handleNetworkError);
};
