import { fetchGraphQl } from '../fetch-graphql';
import {
  GET_ATTRIBUTES_FORM,
  GET_ATTRIBUTES_FORM_SHORT,
} from './graphql/getAttributesForm.graphql';
import { handleNetworkError } from '@/order/lib/network-error';
import { handleFetchError } from '@/order/lib/fetch-error';
import { transformAttributesForm } from '@/order/data/transforms';
import { AttributesFormModel } from '@/order/data/models';
import { GetAttributesFormResponse } from '@/order/types';

export const getAttributesForm = async (
  formCode: string
): Promise<AttributesFormModel[]> => {
  return await fetchGraphQl(
    formCode !== 'shortRequest'
      ? GET_ATTRIBUTES_FORM
      : GET_ATTRIBUTES_FORM_SHORT,
    {
      method: 'GET',
      cache: 'force-cache',
      variables: { formCode },
    }
  )
    .then((response: GetAttributesFormResponse) => {
      if (response.errors?.length) return handleFetchError(response.errors);

      return transformAttributesForm(response?.data?.attributesForm?.items);
    })
    .catch(handleNetworkError);
};
