import { fetchGraphQl } from '@/order/api';
import { handleFetchError } from '@/order/lib/fetch-error';
import { handleNetworkError } from '@/order/lib/network-error';
import { CONFIRM_RETURN_GUEST_ORDER } from './graphql/confirmGuestReturn.graphql';
import { GuestConfirmReturnResponse } from '@/order/types';
import { transformOrderData } from '@/order/data/transforms';
import { events } from '@adobe-commerce/event-bus';
import { OrderDataModel } from '@/order/data/models';

export const confirmGuestReturn = async (
  orderId: string,
  confirmationKey: string
): Promise<OrderDataModel | null> => {
  return await fetchGraphQl(CONFIRM_RETURN_GUEST_ORDER, {
    method: 'POST',
    variables: {
      orderId,
      confirmationKey,
    },
  })
    .then((response: GuestConfirmReturnResponse) => {
      if (response.errors?.length) {
        return handleFetchError(response.errors);
      }

      if (response?.data?.confirmReturn?.return?.order) {
        const transformOrder = transformOrderData(
          // @ts-ignore
          response?.data?.confirmReturn?.return?.order
        );
        events.emit('order/data', transformOrder);

        return transformOrder;
      }

      return null;
    })
    .catch(handleNetworkError);
};
