import { GUEST_ORDER_FRAGMENT } from '@/order/api/fragments';

export const CONFIRM_CANCEL_ORDER_MUTATION = /* GraphQL */ `
  mutation CONFIRM_CANCEL_ORDER_MUTATION(
    $orderId: ID!
    $confirmationKey: String!
  ) {
    confirmCancelOrder(
      input: { order_id: $orderId, confirmation_key: $confirmationKey }
    ) {
      order {
        ...GUEST_ORDER_FRAGMENT
      }
      errorV2 {
        message
        code
      }
    }
  }
  ${GUEST_ORDER_FRAGMENT}
`;
