import { fetchGraphQl } from '@/order/api';
import { handleFetchError } from '@/order/lib/fetch-error';
import { handleNetworkError } from '@/order/lib/network-error';
import { REQUEST_RETURN_GUEST_ORDER } from './graphql/requestGuestReturn.graphql';
import { convertKeysCase } from '@/order/lib/convertCase';
import {
  RequestGuestReturnProps,
  RequestGuestReturnResponse,
} from '@/order/types';

export const requestGuestReturn = async (
  form: RequestGuestReturnProps
): Promise<{
  uid: string;
  number: string;
  status: string;
  createdAt: string;
}> => {
  const input = convertKeysCase(form, 'snakeCase', {});

  return await fetchGraphQl(REQUEST_RETURN_GUEST_ORDER, {
    method: 'POST',
    variables: { input },
  })
    .then((response: RequestGuestReturnResponse) => {
      if (response.errors?.length) return handleFetchError(response.errors);

      const { created_at, ...props } = response.data.requestGuestReturn.return;

      return { ...props, createdAt: created_at };
    })
    .catch(handleNetworkError);
};
