import { events } from '@adobe-commerce/event-bus';
import { getOrderDetailsById } from '../getOrderDetailsById';
import { guestOrderByToken } from '../guestOrderByToken';
import { OrderDataModel } from '@/order/data/models';
import { ConfigProps } from '../initialize';

const QUERY_TYPE = 'orderData';

export const initializeOrderDetails = async (config: ConfigProps) => {
  const orderRef = typeof config?.orderRef === 'string' ? config?.orderRef : '';
  const returnRef =
    typeof config?.returnRef === 'string' ? config?.returnRef : '';

  const isToken =
    orderRef &&
    typeof config?.orderRef === 'string' &&
    config?.orderRef?.length > 20;

  const orderData = (config?.orderData as unknown) ?? null;

  if (orderData) {
    events.emit('order/data', {
      ...orderData,
      returnNumber: returnRef,
    } as OrderDataModel);

    return;
  }

  if (!orderRef) {
    return;
  }

  const responseOrderData = isToken
    ? await guestOrderByToken(orderRef, returnRef)
    : await getOrderDetailsById({
        orderId: orderRef,
        returnRef,
        queryType: QUERY_TYPE,
      });

  if (!responseOrderData) {
    events.emit('order/error', {
      source: 'order',
      type: 'network',
      error: 'The data was not received.',
    });
  } else {
    events.emit('order/data', {
      ...responseOrderData,
      returnNumber: returnRef,
    } as OrderDataModel);
  }
};
