import { fetchGraphQl } from '@/order/api';
import { handleNetworkError } from '@/order/lib/network-error';
import { ORDER_BY_TOKEN } from './graphql/guestOrderByToken.graphql';
import { transformGuestOrderByToken } from '@/order/data/transforms';
import { OrderDataModel } from '@/order/data/models';
import { handleFetchError } from '@/order/lib/fetch-error';

export const guestOrderByToken = async (
  token?: string,
  returnRef?: string
): Promise<OrderDataModel | null> => {
  return await fetchGraphQl(ORDER_BY_TOKEN, {
    method: 'GET',
    cache: 'no-cache',
    variables: { token },
  })
    .then((response) => {
      if (
        response.errors?.length &&
        response.errors[0].message === 'Please login to view the order.'
      ) {
        return handleFetchError(response.errors);
      }

      return transformGuestOrderByToken(response, returnRef);
    })
    .catch(handleNetworkError);
};
