import { OrdersReturnResponseProps } from '@/order/types';
import {
  CustomerOrdersReturnModel,
  OrdersReturnPropsModel,
} from '../models/customer-orders-return';
import { transformOrderItems } from './transform-order-details';
import { config } from '@/order/api';
import { merge } from '@adobe-commerce/elsie/lib';

export const transformCustomerOrdersReturns = (
  returns: OrdersReturnResponseProps
): CustomerOrdersReturnModel | null => {
  if (!returns?.items?.length) return null;

  const ordersList = returns?.items;
  const pageInfo = returns?.page_info;

  const ordersReturn = [...ordersList]
    .sort((a, b) => +b.number - +a.number)
    .map((element) => {
      const { order, status, number, created_at } = element;
      const tracking =
        element?.shipping?.tracking?.map((el) => {
          const { status, carrier, tracking_number } = el;

          return { status, carrier, trackingNumber: tracking_number };
        }) ?? [];

      const items = element.items.map((item) => {
        const quantity = item?.quantity;
        const status = item?.status;
        const request_quantity = item?.request_quantity;
        const uid = item?.uid;
        const order_item = item?.order_item;

        const orderItem =
          transformOrderItems([order_item])?.reduce((_, item) => item, {}) ??
          {};

        return {
          uid,
          quantity,
          status,
          requestQuantity: request_quantity,
          ...orderItem,
        };
      });

      return {
        createdReturnAt: created_at,
        returnStatus: status,
        token: order?.token,
        orderNumber: order?.number,
        returnNumber: number,
        items,
        tracking,
      };
    });

  const model = {
    ordersReturn: ordersReturn as OrdersReturnPropsModel[],
    ...(pageInfo
      ? {
          pageInfo: {
            pageSize: pageInfo.page_size,
            totalPages: pageInfo.total_pages,
            currentPage: pageInfo.current_page,
          },
        }
      : {}),
  };

  return merge(
    model, // default transformer
    config?.getConfig()?.models?.CustomerOrdersReturnModel?.transformer?.({
      ...ordersList,
      ...pageInfo,
    }) // custom transformer
  );
};
