import { fetchGraphQl } from '@/order/api';
import { CANCEL_ORDER_MUTATION } from './graphql/cancelOrderMutation';
import { handleFetchError } from '@/order/lib/fetch-error';
import { transformOrderData } from '@/order/data/transforms';

export const cancelOrder = async (
  orderId: string,
  reason: string,
  onSuccess: Function,
  onError: Function
): Promise<void | null | undefined> => {
  if (!orderId) throw new Error('No order ID found');
  if (!reason) throw new Error('No reason found');

  return fetchGraphQl(CANCEL_ORDER_MUTATION, {
    variables: {
      orderId,
      reason,
    },
  })
    .then(({ errors, data }) => {
      if (errors) return handleFetchError(errors);

      if (data.cancelOrder.error != null) {
        onError();
        return;
      }
      const orderData = transformOrderData(data.cancelOrder.order);
      onSuccess(orderData);
    })
    .catch(() => onError());
};
