import { StoreConfigModel } from '@/order/data/models';

export function transformStoreConfig(data: any): StoreConfigModel | null {
  if (!data) return null;

  return {
    baseMediaUrl: data.base_media_url,
    orderCancellationEnabled: data.order_cancellation_enabled,
    orderCancellationReasons: data.order_cancellation_reasons,
    shoppingOrderDisplayPrice: data.orders_invoices_credit_memos_display_price,
    shoppingOrdersDisplaySubtotal:
      data.orders_invoices_credit_memos_display_subtotal,
    shoppingOrdersDisplayShipping:
      data.orders_invoices_credit_memos_display_shipping_amount,
    shoppingOrdersDisplayGrandTotal:
      data.orders_invoices_credit_memos_display_grandtotal,
    shoppingOrdersDisplayFullSummary:
      data.orders_invoices_credit_memos_display_full_summary,
    shoppingOrdersDisplayZeroTax:
      data.orders_invoices_credit_memos_display_zero_tax,
    salesPrintedCard: +data.sales_printed_card,
    salesGiftWrapping: +data.sales_gift_wrapping,
  };
}
