import { fetchGraphQl } from '@/order/api';
import { handleFetchError } from '@/order/lib/fetch-error';
import { handleNetworkError } from '@/order/lib/network-error';
import { REQUEST_RETURN_ORDER } from './graphql/requestReturn.graphql';
import { convertKeysCase } from '@/order/lib/convertCase';
import { RequestReturnProps, RequestReturnResponse } from '@/order/types';
import { RequestReturnModel } from '@/order/data/models';
import { transformRequestReturn } from '@/order/data/transforms';

export const requestReturn = async (
  form: RequestReturnProps
): Promise<RequestReturnModel | {}> => {
  const input = convertKeysCase(form, 'snakeCase', {});

  return await fetchGraphQl(REQUEST_RETURN_ORDER, {
    method: 'POST',
    variables: { input },
  })
    .then((response: RequestReturnResponse) => {
      if (response.errors?.length) return handleFetchError(response.errors);

      return transformRequestReturn(response);
    })
    .catch(handleNetworkError);
};
