import { RequestReturnResponse } from '@/order/types';
import { RequestReturnModel } from '@/order/data/models';
import { merge } from '@adobe-commerce/elsie/lib';
import { config } from '@/order/api';

export const transformRequestReturn = (
  response: RequestReturnResponse
): RequestReturnModel | {} => {
  if (!response?.data?.requestReturn?.return) return {};

  const { created_at, ...props } = response.data.requestReturn.return;

  const model = { ...props, createdAt: created_at };

  return merge(
    model, // default transformer
    config
      .getConfig()
      ?.models?.RequestReturnModel?.transformer?.(
        response.data.requestReturn.return
      ) // custom transformer
  );
};
