import { GuestOrderByTokenResponse, GuestOrderResponse } from '@/order/types';
import { OrderDataModel } from '../models';
import { transformOrderData } from './transform-order-details';

export const transformGuestOrder = (
  response: GuestOrderResponse,
  returnRef?: string
): OrderDataModel | null => {
  if (!response?.data?.guestOrder) return null;

  const guestOrder = response?.data?.guestOrder;

  return transformOrderData(guestOrder, returnRef);
};

export const transformGuestOrderByToken = (
  response: GuestOrderByTokenResponse,
  returnRef?: string
): OrderDataModel | null => {
  if (!response?.data?.guestOrderByToken) return null;

  const guestOrderByToken = response?.data?.guestOrderByToken;

  return transformOrderData(guestOrderByToken, returnRef);
};
